from dataclasses import dataclass
from typing import Optional, Dict, Any


@dataclass
class PolicyInputs:
    mode: str
    lane: Any
    requested_count: Optional[int]
    complexity_score: float
    resources_percent: int
    model_temperature: float
    model_max_tokens: int
    interactive_self: Any = None
    num_ctx: Optional[int] = None
    num_thread: Optional[int] = None
    # Optional richer signals (currently unused by BasicPolicyProvider)
    context_score: Optional[float] = None
    route_confidence: Optional[float] = None
    time_budget_ms: Optional[int] = None
    qr_tier: Optional[str] = None
    optimizer_hints: Optional[Dict[str, Any]] = None
    rag_relevance: Optional[float] = None
    latency_observed_ms: Optional[int] = None
    mvco_confidence: Optional[float] = None
    memory_pressure: Optional[float] = None


@dataclass
class GenerationPolicy:
    context_entries: int
    include_summary: bool
    directive: str
    overrides: Dict[str, Any]
    options_override: Dict[str, Any]
    token_budget: Optional[int] = None


def compute_generation_policy(
    *,
    mode: str,
    lane: Any,
    requested_count: Optional[int],
    complexity_score: float,
    resources_percent: int,
    model_temperature: float,
    model_max_tokens: int,
    num_ctx: Optional[int] = None,
    num_thread: Optional[int] = None,
) -> GenerationPolicy:
    """Auto-determine context, caps, directive and runtime options.

    This centralizes the heuristics so modes and lanes behave consistently.
    """

    mode = (mode or 'auto').lower()
    lane_name = getattr(lane, 'value', str(lane)).lower()
    task_type = 'standard'
    if lane_name == 'tool_use':
        task_type = 'tool_use'
    elif lane_name == 'deliberate':
        task_type = 'reasoning'
    elif lane_name == 'standard':
        task_type = 'structured' if requested_count else 'standard'

    # Context window policy
    if mode.startswith('fast'):
        context_entries = 1
        include_summary = False
    elif mode.startswith('think'):
        context_entries = 5
        include_summary = True
    else:
        context_entries = 4
        include_summary = False

    # Token caps per mode × task type
    # Fast mode: more aggressive caps for snappy responses
    caps_fast = {'standard': 100, 'structured': 60, 'reasoning': 150}
    caps_auto = {'standard': 300, 'structured': 220, 'reasoning': 450}
    caps_think = {'standard': 600, 'structured': 350, 'reasoning': 900}

    if mode.startswith('fast'):
        cap = caps_fast.get(task_type, 256)
        read_to = 30.0
    elif mode.startswith('think'):
        # Respect an implicit budget hint from resources/complexity (soft)
        cap = caps_think.get(task_type, 800)
        read_to = 120.0
    else:
        cap = caps_auto.get(task_type, 400)
        read_to = 60.0

    # Temperature nudges for structured lists
    temp = None
    if task_type == 'structured':
        temp = max(0.0, float(model_temperature) - 0.15)

    # Build structured directive when count is requested
    directive = ''
    if task_type == 'structured':
        if requested_count:
            directive = (
                f"\n\nInstructions: Return exactly {requested_count} items as a compact hyphen list. "
                f"One short line per item. No extra sentences before or after the list."
            )
        else:
            directive = (
                "\n\nInstructions: Return a compact hyphen list with one short line per item. "
                "No extra sentences before or after the list."
            )

    overrides = {
        'num_predict_override': int(max(1, min(model_max_tokens, cap))),
        'temperature_override': temp,
        # No read timeout: rely on governor/confirmation instead of hard timeouts
    }

    options_override: Dict[str, Any] = {}
    if num_ctx:
        options_override['num_ctx'] = int(num_ctx)
    if num_thread:
        options_override['num_thread'] = int(num_thread)

    return GenerationPolicy(
        context_entries=context_entries,
        include_summary=include_summary,
        directive=directive,
        overrides=overrides,
        options_override=options_override,
    )


class PolicyProvider:
    def decide(self, inputs: PolicyInputs) -> GenerationPolicy:
        raise NotImplementedError


class BasicPolicyProvider(PolicyProvider):
    def decide(self, inputs: PolicyInputs) -> GenerationPolicy:
        # Delegate to the existing function; ignore richer signals for now
        return compute_generation_policy(
            mode=inputs.mode,
            lane=inputs.lane,
            requested_count=inputs.requested_count,
            complexity_score=inputs.complexity_score,
            resources_percent=inputs.resources_percent,
            model_temperature=inputs.model_temperature,
            model_max_tokens=inputs.model_max_tokens,
            num_ctx=inputs.num_ctx,
            num_thread=inputs.num_thread,
        )


class AdaptivePolicyProvider(PolicyProvider):
    """Adaptive provider that scales budgets by requested_count and complexity.

    Modes primarily influence style and default context size; budgets expand
    with input size and complexity instead of fixed caps.
    """

    def decide(self, inputs: PolicyInputs) -> GenerationPolicy:
        mode = (inputs.mode or 'auto').lower()
        lane_name = getattr(inputs.lane, 'value', str(inputs.lane)).lower()
        is_structured = lane_name == 'standard' and inputs.requested_count

        # Incremental context logic
        if inputs.interactive_self:
            if lane_name in ('recall', 'deliberate'):
                context_entries = 8
            elif lane_name == 'standard' and not is_structured:
                inputs.interactive_self._conversational_context_size = min(8, inputs.interactive_self._conversational_context_size + 1)
                context_entries = inputs.interactive_self._conversational_context_size
            elif lane_name == 'tool_use' or is_structured:
                inputs.interactive_self._conversational_context_size = 3
                context_entries = inputs.interactive_self._conversational_context_size
            else:
                context_entries = inputs.interactive_self._conversational_context_size
        else:
            # Fallback for stateless calls
            context_entries = 4

        # Style by mode
        if mode.startswith('fast'):
            include_summary = False
            avg_item_len = 6
            avg_item_time = 0.12
        elif mode.startswith('think'):
            include_summary = True
            avg_item_len = 18
            avg_item_time = 0.6
        else:  # auto/smart/custom
            include_summary = False
            avg_item_len = 12
            avg_item_time = 0.4

        # Base budgets
        requested_count = inputs.requested_count or 0
        complexity = max(0.0, min(1.0, float(inputs.complexity_score or 0.0)))

        # Token budget scales with requested_count when structured
        is_structured = lane_name == 'standard' and requested_count
        if is_structured:
            base = 40
            tokens = int(base + requested_count * avg_item_len * (1.1 + 0.5 * complexity))
        else:
            # Non-structured: moderate budget scaled by complexity
            tokens = int(200 + 400 * complexity)

        # Clamp by model limits
        tokens = max(40, min(int(inputs.model_max_tokens or 2048), tokens))

        # Read timeout scales with size/complexity; allow larger for think
        base_to = 25.0 if mode.startswith('fast') else (60.0 if mode.startswith('think') else 40.0)
        extra = requested_count * avg_item_time * (1.0 + 0.5 * complexity)
        # No hard read timeouts; rely on confirmations/governor

        # Task type mapping
        task_type = 'standard'
        if lane_name == 'tool_use':
            task_type = 'tool_use'
        elif lane_name == 'deliberate':
            task_type = 'reasoning'
        elif lane_name == 'standard':
            task_type = 'structured' if requested_count else 'standard'

        # Temperature nudge for structured lists (more deterministic)
        temp = None
        if task_type == 'structured':
            try:
                temp = max(0.0, float(inputs.model_temperature) - 0.2)
            except Exception:
                temp = None

        # Stronger directive for strict list formatting
        directive = ''
        if task_type == 'structured':
            if requested_count:
                directive = (
                    f"\n\nInstructions: Return exactly {requested_count} lines, each starting with '- '. "
                    "Only hyphen bullets; no headings, no numbering, no blank lines, no extra text."
                )
            else:
                directive = (
                    "\n\nInstructions: Return hyphen-bullet lines only. One concise line per item. "
                    "No headings, numbering, or extra text."
                )

        overrides = {
            'num_predict_override': int(tokens),
            'temperature_override': temp,
            # no read timeouts
        }

        options_override: Dict[str, Any] = {}
        if inputs.num_ctx:
            options_override['num_ctx'] = int(inputs.num_ctx)
        if inputs.num_thread:
            options_override['num_thread'] = int(inputs.num_thread)

        return GenerationPolicy(
            context_entries=context_entries,
            include_summary=include_summary,
            directive=directive,
            overrides=overrides,
            options_override=options_override,
            token_budget=tokens,
        )
